Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        var client = new HttpClient(_handler) { BaseAddress = new Uri("https://example.com") };
        _fetcher = new DataFetcher(client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world")
        };

        var result = await _fetcher.FetchAsync("https://example.com/data",
            _testContext.CancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync("https://example.com/missing",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        _handler.Delay = TimeSpan.FromSeconds(30);
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    // Minimal test double — no mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return Response;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task`, use `await` — never `async void` |
| **Timeouts** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` to the code under test |
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Constructor init** | Fields are `readonly`, `TestContext` injected via constructor (MSTest 3.6+) |
| **Sealed class** | `sealed` on both test class and handler for clarity and perf |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking library needed |

The `[Timeout]` attribute cancels `TestContext.CancellationToken` when the timeout elapses, so passing it through to your production code ensures the test genuinely aborts rather than hanging.
